solutions.python:
class Solution:
    def validateExposedPorts(self, composeFile: str) -> bool:
        import yaml
        config = yaml.safe_load(composeFile)
        if not config or 'services' not in config:
            return False
        services = config['services']
        for service in services.values():
            if 'expose' in service:
                for port in service['expose']:
                    if int(port) == 22 or int(port) > 65535:
                        return False
        return True
